import{c as a,Q as t,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I update environment variables on an instance?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/update-env-vars.md","filePath":"guide/recipes/admin/update-env-vars.md","lastUpdated":1778912818000}'),i={name:"guide/recipes/admin/update-env-vars.md"};function r(o,e,l,c,d,h){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-update-environment-variables-on-an-instance" tabindex="-1">How do I update environment variables on an instance? <a class="header-anchor" href="#how-do-i-update-environment-variables-on-an-instance" aria-label="Permalink to &quot;How do I update environment variables on an instance?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>Environment variables are managed per service per instance. The Services tab on the instance detail page shows the current values, any drift, and lets you set or remove overrides.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Instances</strong> and click the target instance.</li><li>Switch to the <strong>Services</strong> tab.</li><li>Find the service whose env you need to change. Drift (expected vs. actual) is shown inline if the running instance reports a different value than what the Console expects.</li><li>Expand the service row to see its variables.</li><li>For each variable: <ul><li><strong>Set Override</strong> to add or change a value.</li><li><strong>Remove Override</strong> to fall back to the service default.</li></ul></li><li>Click <strong>Apply Changes</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The instance receives the new env on its next reconciliation tick (usually within a minute). The Services tab refreshes drift indicators as soon as the instance acknowledges the new values.</p><div class="tip custom-block"><p class="custom-block-title">Roll out broadly via Releases</p><p>For multi-instance changes — like bumping a service image — use <a href="./create-release">create a release</a> instead. It&#39;s the audited path for fleet-wide rollouts.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-release">How do I create a release?</a></li></ul>',10)])])}const v=a(i,[["render",r]]);export{p as __pageData,v as default};
